import React from 'react';

const Item = ({item}) => {
    return (
        <div className="item">
            <input type='checkbox' defaultChecked={item.done}/>
            <span>{item.title}</span>
            <button className='remove-btn'>Delete</button>
        </div>
    );
}

export default Item;
